#include <bits/stdc++.h>
using namespace std;
int a[20],vis[10][30],ans,n;
void dfs(int x) {
	if(x>n) {
		ans++;
		if(ans>3) {
			return;
		} else {
			for(int i=1; i<=n; i++) {
				cout<<a[i]<<" ";
			}
			cout<<"\n";
			return;
		}
	}
	for(int i=1; i<=n; i++) {
		if((!vis[0][i])&&(!vis[1][x+i])&&(!vis[2][x-i+n])) {
			a[x]=i;
			vis[0][i]=vis[1][x+i]=vis[2][x-i+n]=1;
			dfs(x+1);
			vis[0][i]=vis[1][x+i]=vis[2][x-i+n]=0;
		}
	}
}
int main() {
	cin>>n;
	dfs(1);
	cout<<ans;
	return 0;
}
